// Put the implementation in a struct so we don't pollute the top-level namespace
fileprivate struct UniffiCallbackInterfaceMergeResolverCallback {

    // Create the VTable using a series of closures.
    // Swift automatically converts these into C callback functions.
    //
    // This creates 1-element array, since this seems to be the only way to construct a const
    // pointer that we can pass to the Rust code.
    static let vtable: [UniffiVTableCallbackInterfaceMergeResolverCallback] = [UniffiVTableCallbackInterfaceMergeResolverCallback(
        uniffiFree: { (uniffiHandle: UInt64) -> () in
            do {
                try FfiConverterTypeMergeResolverCallback.handleMap.remove(handle: uniffiHandle)
            } catch {
                print("Uniffi callback interface MergeResolverCallback: handle missing in uniffiFree")
            }
        },
        uniffiClone: { (uniffiHandle: UInt64) -> UInt64 in
            do {
                return try FfiConverterTypeMergeResolverCallback.handleMap.clone(handle: uniffiHandle)
            } catch {
                fatalError("Uniffi callback interface MergeResolverCallback: handle missing in uniffiClone")
            }
        },
        resolve: { (
            uniffiHandle: UInt64,
            conflict: RustBuffer,
            uniffiOutReturn: UnsafeMutablePointer<RustBuffer>,
            uniffiCallStatus: UnsafeMutablePointer<RustCallStatus>
        ) in
            let makeCall = {
                () throws -> ResolutionRecord in
                guard let uniffiObj = try? FfiConverterTypeMergeResolverCallback.handleMap.get(handle: uniffiHandle) else {
                    throw UniffiInternalError.unexpectedStaleHandle
                }
                return uniffiObj.resolve(
                     conflict: try FfiConverterTypeConflictRecord_lift(conflict)
                )
            }


            let writeReturn = { uniffiOutReturn.pointee = FfiConverterTypeResolutionRecord_lower($0) }
            uniffiTraitInterfaceCall(
                callStatus: uniffiCallStatus,
                makeCall: makeCall,
                writeReturn: writeReturn
            )
        }
    )]
