public struct FfiConverterTypeProllyBlobStore: FfiConverter {
    typealias FfiType = UInt64
    typealias SwiftType = ProllyBlobStore

    public static func lift(_ handle: UInt64) throws -> ProllyBlobStore {
        return ProllyBlobStore(unsafeFromHandle: handle)
    }

    public static func lower(_ value: ProllyBlobStore) -> UInt64 {
        return value.uniffiCloneHandle()
    }

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> ProllyBlobStore {
        let handle: UInt64 = try readInt(&buf)
        return try lift(handle)
    }

    public static func write(_ value: ProllyBlobStore, into buf: inout [UInt8]) {
        writeInt(&buf, lower(value))
    }
}


