            do {
                return try FfiConverterTypeSecondaryIndexExtractorCallback.handleMap.clone(handle: uniffiHandle)
            } catch {
                fatalError("Uniffi callback interface SecondaryIndexExtractorCallback: handle missing in uniffiClone")
            }
        },
